CREATE DATABASE IF NOT EXISTS account_db; USE account_db;
CREATE TABLE IF NOT EXISTS account_types (id BIGINT PRIMARY KEY AUTO_INCREMENT, code VARCHAR(30) NOT NULL UNIQUE, name VARCHAR(100) NOT NULL, minimum_balance DECIMAL(18,2) NOT NULL DEFAULT 0.00, daily_transfer_limit DECIMAL(18,2) NOT NULL DEFAULT 0.00);
CREATE TABLE IF NOT EXISTS accounts (id BIGINT PRIMARY KEY AUTO_INCREMENT, account_number VARCHAR(30) NOT NULL UNIQUE, customer_id BIGINT NOT NULL, account_type_id BIGINT NOT NULL, currency_code VARCHAR(10) NOT NULL, current_balance DECIMAL(18,2) NOT NULL DEFAULT 0.00, available_balance DECIMAL(18,2) NOT NULL DEFAULT 0.00, status VARCHAR(30) NOT NULL, opened_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_accounts_account_type FOREIGN KEY (account_type_id) REFERENCES account_types(id));
INSERT IGNORE INTO account_types(id,code,name,minimum_balance,daily_transfer_limit) VALUES (1,'CHK','Checking Account',0.00,10000.00),(2,'SAV','Savings Account',100.00,5000.00);
